fn insert_metadata<T: ClaritySerializable>(
    &mut self,
    contract_identifier: &QualifiedContractIdentifier,
    key: &str,
    data: &T,
) -> Result<(), VmExecutionError> {
    if self.store.has_metadata_entry(contract_identifier, key) {
        Err(VmInternalError::Expect(format!(
            "Metadata entry '{key}' already exists for contract: {contract_identifier}"
        ))
        .into())
    } else {
        self.store
            .insert_metadata(contract_identifier, key, &data.serialize())
            .map_err(|e| e.into())
    }
}

#[cfg_attr(feature = "profiler", stacks_profiler::profile)]
fn fetch_metadata<T>(
    &mut self,
    contract_identifier: &QualifiedContractIdentifier,
    key: &str,
) -> Result<Option<T>, VmExecutionError>
where
    T: ClarityDeserializable<T>,
{
    let x_opt = self.store.get_metadata(contract_identifier, key)?;
    match x_opt {
        None => Ok(None),
        Some(x) => T::deserialize(&x).map(|out| Some(out)),
    }
}

#[cfg_attr(feature = "profiler", stacks_profiler::profile)]
pub fn fetch_metadata_manual<T>(
    &mut self,
