    pub fn new(
        store: &'b mut dyn ClarityBackingStore,
        header_db: &'a dyn HeadersDB,
        burn_state_db: &'a dyn BurnStateDB,
        cost_track: &'a mut Option<LimitedCostTracker>,
        mainnet: bool,
        chain_id: u32,
