    ) -> ClarityTransactionConnection<'a, 'b> {
        let mut log = RollbackWrapperPersistedLog::new();
        log.nest();
        ClarityTransactionConnection {
            log: Some(log),
            store,
            header_db,
            burn_state_db,
            cost_track,
            mainnet,
            chain_id,
            epoch,
        }
    }
}

