+        {
+            let mut wrapper = RollbackWrapper::new(&mut store);
+            wrapper.nest();
+            wrapper.set_block_hash(block.clone(), false).unwrap();
+
+            let first = wrapper
+                .get_value(
+                    "value-key",
+                    &TypeSignature::IntType,
+                    &StacksEpochId::Epoch25,
+                )
+                .unwrap()
+                .unwrap();
+            let second = wrapper
+                .get_value(
+                    "value-key",
+                    &TypeSignature::IntType,
+                    &StacksEpochId::Epoch25,
+                )
+                .unwrap()
+                .unwrap();
